#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

struct Enemy {
    std::string name;
    int health;
    int attack;
};

int main() {
    std::cout << "=== Lambda Functions ===" << std::endl;

    // 1. Basic lambda
    std::cout << "\n--- Basic Lambda ---" << std::endl;
    auto greet = []() {
        std::cout << "Hello from Lambda!" << std::endl;
    };
    greet();

    // 2. Lambda with parameters
    std::cout << "\n--- Lambda with Parameters ---" << std::endl;
    auto add = [](int a, int b) {
        return a + b;
    };
    std::cout << "5 + 3 = " << add(5, 3) << std::endl;

    // 3. Lambda with capture (by value)
    std::cout << "\n--- Capture by Value ---" << std::endl;
    int multiplier = 3;
    auto multiply = [multiplier](int x) {
        return x * multiplier;
    };
    std::cout << "5 * 3 = " << multiply(5) << std::endl;

    // 4. Lambda with capture (by reference)
    std::cout << "\n--- Capture by Reference ---" << std::endl;
    int counter = 0;
    auto increment = [&counter]() {
        counter++;
        return counter;
    };
    std::cout << increment() << std::endl;
    std::cout << increment() << std::endl;
    std::cout << "Counter: " << counter << std::endl;

    // 5. Lambda with capture all
    std::cout << "\n--- Capture All ---" << std::endl;
    int a = 10, b = 20;
    auto sum = [=]() { return a + b; };  // [=] captures all by value
    auto modify = [&]() { a += 5; b += 5; };  // [&] captures all by reference

    std::cout << "Sum: " << sum() << std::endl;
    modify();
    std::cout << "After modify: a=" << a << ", b=" << b << std::endl;

    // 6. Lambda with explicit return type
    std::cout << "\n--- Explicit Return Type ---" << std::endl;
    auto divide = [](double x, double y) -> double {
        if (y != 0) return x / y;
        return 0.0;
    };
    std::cout << "10 / 3 = " << divide(10, 3) << std::endl;

    // 7. Using lambdas with STL algorithms
    std::cout << "\n--- Lambdas with STL ---" << std::endl;
    std::vector<int> numbers = {10, 20, 30, 40, 50};

    // Sort descending
    std::sort(numbers.begin(), numbers.end(), [](int x, int y) {
        return x > y;
    });
    std::cout << "Sorted descending: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    // Count even numbers
    int evens = std::count_if(numbers.begin(), numbers.end(), [](int n) {
        return n % 2 == 0;
    });
    std::cout << "Even numbers: " << evens << std::endl;

    // 8. Game use: filtering enemies
    std::cout << "\n--- Game: Filter Enemies ---" << std::endl;
    std::vector<Enemy> enemies = {
        {"Goblin", 30, 8},
        {"Orc", 50, 12},
        {"Boss", 200, 25},
        {"Skeleton", 25, 6}
    };

    // Find enemies with health > 40
    auto strongEnemies = std::count_if(enemies.begin(), enemies.end(),
        [](const Enemy& e) { return e.health > 40; });
    std::cout << "Strong enemies (HP > 40): " << strongEnemies << std::endl;

    // Find first enemy with attack > 15
    auto it = std::find_if(enemies.begin(), enemies.end(),
        [](const Enemy& e) { return e.attack > 15; });
    if (it != enemies.end()) {
        std::cout << "First high-attack enemy: " << it->name << std::endl;
    }

    std::cout << "\n--- Lambda Syntax Summary ---" << std::endl;
    std::cout << "[capture](parameters) -> return_type { body }" << std::endl;
    std::cout << "[=]  → capture all by value" << std::endl;
    std::cout << "[&]  → capture all by reference" << std::endl;
    std::cout << "[x]  → capture x by value" << std::endl;
    std::cout << "[&x] → capture x by reference" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>

int main() {
    int x = 10;
    int y = 20;

    // Forgetting to capture x!
    auto lambda = []() {
        return x + y;  // ERROR! x and y not captured
    };

    std::cout << lambda() << std::endl;
    return 0;
}

phase2.explanation:
You tried to use `x` and `y` in a lambda without capturing them!

**The fix:**
```cpp
auto lambda = [x, y]() {  // Capture by value
    return x + y;
};
```

**Or capture all:**
```cpp
auto lambda = [=]() {  // Capture all by value
    return x + y;
};
```

**PlusPlus-chan says:**
"Lambdas can only access variables they capture. If you need them, capture them."

phase3.solution:
#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> numbers = {5, 12, 7, 20, 15, 3, 18};

    std::cout << "Original: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    std::sort(numbers.begin(), numbers.end(), 
              [](int a, int b) { return a < b; });

    std::cout << "Sorted: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    int greaterThan10 = std::count_if(numbers.begin(), numbers.end(),
                                       [](int n) { return n > 10; });
    std::cout << "Numbers > 10: " << greaterThan10 << std::endl;

    auto it = std::find_if(numbers.begin(), numbers.end(),
                            [](int n) { return n % 2 == 0; });
    if (it != numbers.end()) {
        std::cout << "First even number: " << *it << std::endl;
    }

    std::for_each(numbers.begin(), numbers.end(),
                  [](int& n) { n *= 2; });

    std::cout << "After doubling: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    return 0;
}
